package com.yourmod.entity;import net.minecraft.world.entity.EntityType;import net.minecraft.world.entity.ai.attributes.AttributeSupplier;import net.minecraft.world.entity.ai.attributes.Attributes;import net.minecraft.world.entity.ai.goal.*;import net.minecraft.world.entity.monster.Monster;import net.minecraft.world.entity.player.Player;import net.minecraft.world.level.Level;public class ShadowAssassinEntity extends Monster {        public ShadowAssassinEntity(EntityType&lt;? extends Monster&gt; type, Level level) {        super(type, level);    }        @Override    protected void registerGoals() {        this.goalSelector.addGoal(0, new FloatGoal(this));        this.goalSelector.addGoal(1, new MeleeAttackGoal(this, 1.2D, false));        this.goalSelector.addGoal(2, new WaterAvoidingRandomStrollGoal(this, 1.0D));        this.goalSelector.addGoal(3, new LookAtPlayerGoal(this, Player.class, 8.0F));        this.goalSelector.addGoal(4, new RandomLookAroundGoal(this));                this.targetSelector.addGoal(1, new HurtByTargetGoal(this));        this.targetSelector.addGoal(2, new NearestAttackableTargetGoal&lt;&gt;(this, Player.class, true));    }        public static AttributeSupplier.Builder createAttributes() {        return Monster.createMonsterAttributes()            .add(Attributes.MAX_HEALTH, 40.0D)            .add(Attributes.MOVEMENT_SPEED, 0.35D)            .add(Attributes.ATTACK_DAMAGE, 8.0D)            .add(Attributes.ARMOR, 4.0D)            .add(Attributes.FOLLOW_RANGE, 32.0D);    }}

