package com.yourmod.world.capabilities;import yesman.epicfight.world.capabilities.entitypatch.MobPatch;import yesman.epicfight.world.capabilities.entitypatch.Faction;import yesman.epicfight.api.animation.LivingMotions;import com.yourmod.entity.ShadowAssassinEntity;import com.yourmod.animations.ShadowAssassinAnimations;public class ShadowAssassinPatch extends MobPatch&lt;ShadowAssassinEntity&gt; {        public ShadowAssassinPatch() {        super(Faction.HOSTILE);    }        @Override    public void initAnimator() {        super.initAnimator();                // 设置基础动作        this.animator.addLivingAnimation(LivingMotions.IDLE, ShadowAssassinAnimations.ASSASSIN_IDLE);        this.animator.addLivingAnimation(LivingMotions.WALK, ShadowAssassinAnimations.ASSASSIN_WALK);        this.animator.addLivingAnimation(LivingMotions.CHASE, ShadowAssassinAnimations.ASSASSIN_WALK);    }        @Override    public void updateMotion(boolean considerInaction) {        super.updateMotion(considerInaction);                // 自定义运动逻辑        if (this.state.inaction()) {            currentMotion = LivingMotions.IDLE;        } else if (this.getOriginal().getDeltaMovement().horizontalDistanceSqr() &gt; 0.01D) {            currentMotion = LivingMotions.WALK;        } else {            currentMotion = LivingMotions.IDLE;        }    }        // 自定义攻击逻辑    public void performBackstab() {        if (!this.isLogicalClient()) {            this.playAnimationSynchronized(ShadowAssassinAnimations.ASSASSIN_BACKSTAB, 0.0F);        }    }        public void enterStealth() {        if (!this.isLogicalClient()) {            this.playAnimationSynchronized(ShadowAssassinAnimations.ASSASSIN_STEALTH, 0.0F);        }    }}

