第七步: 创建 AI 目标 (背刺逻辑)BackstabGoal.java:
package com.yourmod.entity.ai;import net.minecraft.world.entity.LivingEntity;import net.minecraft.world.entity.ai.goal.Goal;import net.minecraft.world.phys.Vec3;import yesman.epicfight.world.capabilities.EpicFightCapabilities;import com.yourmod.entity.ShadowAssassinEntity;import com.yourmod.world.capabilities.ShadowAssassinPatch;import java.util.EnumSet;public class BackstabGoal extends Goal {        private final ShadowAssassinEntity assassin;    private LivingEntity target;    private int cooldown = 0;        public BackstabGoal(ShadowAssassinEntity assassin) {        this.assassin = assassin;        this.setFlags(EnumSet.of(Goal.Flag.MOVE, Goal.Flag.LOOK));    }        @Override    public boolean canUse() {        if (cooldown &gt; 0) {            cooldown--;            return false;        }                this.target = this.assassin.getTarget();        if (target == null) {            return false;        }                // 检查是否在目标背后        return isBehin dTarget();    }        @Override    public void start() {        // 执行背刺        this.assassin.getCapability(EpicFightCapabilities.CAPABILITY_ENTITY).ifPresent(cap -&gt; {            if (cap instanceof ShadowAssassinPatch patch) {                patch.performBackstab();            }        });                // 设置冷却时间        cooldown = 200; // 10秒    }        private boolean isBehindTarget() {        Vec3 assassinPos = this.assassin.position();        Vec3 targetPos = this.target.position();        Vec3 targetLook = this.target.getLookAngle();                Vec3 toAssassin = assassinPos.subtract(targetPos).normalize();        double dot = targetLook.dot(toAssassin);                // 如果点积小于-0.5,说明刺客在目标背后        return dot &lt; -0.5 &amp;&amp; this.assassin.distanceTo(this.target) &lt; 3.0;    }}

